+    const motionPower = preStumble ? 0.08
+      : stumbling ? 0.15 + stumbleIntensity * 0.3
+      : inFall ? 0.6 + impactSpike * 0.4
+      : microMovement ? 0.05 + microIntensity * 0.15
+      : 0.02 + Math.abs(n.motion(t)) * 0.005;
