+  0.01, // 4 right ear
+  0.03, // 5 left shoulder
+  0.03, // 6 right shoulder
+  0.05, // 7 left elbow
+  0.05, // 8 right elbow
+  0.08, // 9 left wrist
+  0.08, // 10 right wrist
+  0.02, // 11 left hip
+  0.02, // 12 right hip
